-- 2026-06-14 · SLKO 교육자료 추가: 슬라임 피크닉 운영 매뉴얼 (스타필드 죽전)
-- ----------------------------------------------------------------------------
-- 원본: 슬라라 슬라임 피크닉 교육매뉴얼 PPT(17슬라이드)를 PDF로 렌더링해 슬라이드별
--       이미지(/assets/manuals/slko-slime-picnic/slideNN.jpg, Vercel 서빙)로 보존.
-- 구조: 챕터 1개 + 섹션 1개(17 scene = 슬라이드별 이미지+설명) + 슬라이드별 퀴즈 17문항.
-- 격리: company_id = SLKO('f7b86b4d-9a43-486d-8d07-6ba812cd4ef7') 로 고정 — Kiwooza 등 타 브랜드엔 절대 안 보임.
-- 멱등: id 고정 + ON CONFLICT DO UPDATE 라 재실행 안전(내용 갱신).
-- 적용: Supabase → SQL Editor 에 붙여넣고 Run.
-- ----------------------------------------------------------------------------
begin;

-- 1) 챕터
insert into public.sop_documents
  (id, title, category, content, status, order_num, doc_type, parent_id, company_id, created_at, updated_at)
