-- 2) 섹션(17 scene + 17 퀴즈)
insert into public.sop_documents
  (id, title, category, content, status, order_num, script, quizzes, doc_type, parent_id, company_id, created_at, updated_at)
values
  ('sop-slko-slime-picnic', '슬라임 피크닉 교육매뉴얼', '운영 매뉴얼',
   '스타필드마켓 죽전 1F 슬라라 슬라임 피크닉 팝업 운영 교육매뉴얼입니다. 슬라이드 17장(가격·체험 흐름·운영·안전·연락망)을 순서대로 학습하세요.',
   'published', 1,
   '[{"scene": 1, "visual": "표지", "narration": "슬라임 피크닉 교육매뉴얼입니다. 장소는 스타필드마켓 죽전 1F(롯데 팝업), 주최 ㈜슬코 · 브랜드 슬라라(슬라라 / 슬라라mini / 슬라임팝업). 가족·어린이 대상 행사입니다.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide01.jpg"}, {"scene": 2, "visual": "체험 한눈에", "narration": "기본 체험 요금 18,000원, 체험 시간 1시간. 체험 게임은 3종(아이스크림 슬라임, 뮤지컬 연계 테마 등)이며 게임 2종 + 자유 2종으로 운영합니다. 리워드 시스템으로 인스타 게시물 & 팔로우 이벤트를 진행하고, 프리미엄 고급 콘텐츠를 제공합니다.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide02.jpg"}, {"scene": 3, "visual": "INDEX · 행사 목표", "narration": "브랜드 슬라라의 가치는 ‘재미, 친절, +1’입니다. 아이들이 웃으며 즐겁게 놀다 갈 수 있도록 행사기간 동안 한 번이라도 더 아이들과 소통해 주세요. 행사 중요 목표: ① 영종도 인스파이어 슬라라 매장 홍보(@slalaa_world), ② 매출 향상. 첫 스텝은 인사입니다 — ‘안녕하세요! 슬라라입니다!!!’. 행사 기간 05.29~06.10, 종료(철수)는 06.11 14시부터입니다.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide03.jpg"}, {"scene": 4, "visual": "패키지 구조 및 가격", "narration": "기본 패키지 구성: 슬라임 빙수만들기 DIY + 아이스크림 슬라임 + 파츠 + 스탬프 팜플렛·구디백·스티커 — 18,000원/1인. 기본 게임 2종 중 1종 진행 포함. 권장 연령 만 3세 이상(8세 이하 보호자 동반 필수). 정원 아동 70명 기준. 체험 시간 1시간. 예약 없음/현장결제. 게임 1종 추가 진행 시 +3,000원(추가 게임 진행자에게는 파츠 1컵 담을 수 있는 컵 제공).", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide04.jpg"}, {"scene": 5, "visual": "체험 5단계 흐름 · 진행 스크립트", "narration": "체험 흐름: ① 현장 결제 ② 슬라임 빙수만들기(18,000원) ③ 플레잉존 1시간 체험 ④ 미니게임 3종 중 택1 ⑤ 리워드 슬라임으로 슬라임월에 붙이고 사진찍기. 체험 종류: 눈꽃슬라임, 대형 바닥풍선, 얼음 낚시. 아이스크림 마차에서 슬라임 아이스크림 선택 후 플레잉존으로 이동. 바닥풍선(바풍) 스크립트 — 인사 ‘안녕하세요, 슬라라 바풍존입니다.’ 진행 ‘먼저 연습 한 번 해보시고요’, ‘이제 본게임 진행하겠습니다! 준비되셨으면 시작해주세요!’ 마무리 ‘체험 완료되었습니다.’", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide05.jpg"}, {"scene": 6, "visual": "슬라임카페 · 구성품 · 추가구매 · 응대", "narration": "슬라임 아이스크림 = 슬라임카페. DIY 아이스크림 슬라임 + 파츠 + 스탬프 팜플렛·구디백·스티커 18,000원/1인. 카운터에서 스티커 뒷면에 체험 끝나는 시간 적기(예: 13:00→14:00), 1시간 이용 안내. 구성품: 구디백·컵·컵뚜껑·스티커·체험권. 추가구매 — 아이스크림 12,000원, 파츠 1통 3,000원, 토핑 2,000원. 스티커는 구디백 꾸미는 용도라고 설명. 머리 긴 친구에겐 머리끈 하나씩! Q ‘여기 뭐하는 거에요?’ A ‘슬라임카페입니다. 18,000원이고 앉아서 하실 수 있는 키트를 다 드려요! 추가로 옆 두 게임 중 한 가지 할 수 있는 티켓을 드립니다.’", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide06.jpg"}, {"scene": 7, "visual": "현장 사진", "narration": "체험존 현장 모습입니다.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide07.jpg"}, {"scene": 8, "visual": "오픈 · 마감 매뉴얼", "narration": "오픈/마감 매뉴얼: 바닥청소. 오픈 후 체험존·굿즈존 사진을 단톡방에 공유. 하역장 쓰레기는 그날그날 처리. 본부장님께 개인톡으로 보고.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide08.jpg"}, {"scene": 9, "visual": "슬라임 월 (포토존)", "narration": "슬라임 월 — ‘나의 빙수슬라임으로 슬라임월을 꾸며보자!’ 나의 아이스크림 슬라임 또는 인스타 이벤트 리워드로 받은 슬라임을 붙이고 사진도 찍는 포토존 체험. 자유롭게 참여 가능, 아이스크림 슬라임 일부 사용. 슬라임 컬러: 파랑·하늘·하양.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide09.jpg"}, {"scene": 10, "visual": "체험 상세 — 대형 바닥풍선", "narration": "체험 콘텐츠 상세 — 대형 바닥풍선: 강사(슬라임 선생님)와 협동하여 바닥 풍선을 아주 크게 만드는 팀빌딩 챌린지. 2인 1조, 연습 1회 + 본 도전 1회. 장비: 대용량 슬라임. 운영 포인트: 2인 1조 강사 배치, 성공률 97%, 평균 3분 소요, 최대 3인 참여. 두 게임 성공 시 리워드(1게임은 추가결제), 파츠 1컵.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide10.jpg"}, {"scene": 11, "visual": "체험 상세 — 슬라임 던지기", "narration": "체험 콘텐츠 상세 — 슬라임 던지기(찐득볼): 부모님은 뒤에 들어가 있고 아이가 던지는 팀빌딩 게임(부모님 또는 강사 맞추기). 연습 1회 + 본 도전 1회, 3번 던져 70점. 장비: 글로블스. 운영 포인트: 1인 1조 강사 배치, 성공률 80%, 평균 1분 소요, 최대 1인 참여. 두 게임 성공 시 리워드(1게임은 추가결제), 파츠 1컵.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide11.jpg"}, {"scene": 12, "visual": "공간 구성 · 존 운영안 (50평)", "narration": "공간 구성 및 존 운영안 — 죽전점 50평. DIY존 / 체험존 / 굿즈존 배치, 동선, 안전 기준. 입구 → 카운터 → DIY존·굿즈존·체험존.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide12.jpg"}, {"scene": 13, "visual": "주차 · FAQ · 비상연락망 · 안전 · POS", "narration": "주차장 이용 안내, 자주 묻는 질문, 비상연락망. 이마트 측 — 정 정우민 AM 010-8466-5541 / 부 윤지호 대리 010-9925-5833. 슬라라 측 — 정 이학규 본부장 010-4065-2845 / 부 장진호 선임 010-8581-0381. 슬라임 이용: 본 슬라임은 KC 인증 기준에 맞춰 제작된 안전한 제품. 단 먹거나 눈·입에 넣지 않도록 주의, 의류·신발에 묻을 수 있어 편한 복장 권장. 오염 시 미온수+식초로 녹인 후 세탁(강하게 문지르면 번지므로 가볍게 떼어낸 후 세탁), 소재에 따라 얼룩이 남을 수 있으며 별도 보상·책임은 어려움. POS 아이디 870070 / 비번 00000. 결제 시 ‘신세계 포인트 적립하시겠어요?’ 꼭 여쭤보기.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide13.jpg"}, {"scene": 14, "visual": "직원식당 위치", "narration": "직원식당 위치 안내입니다.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide14.jpg"}, {"scene": 15, "visual": "출입구 위치", "narration": "출입구 위치 안내입니다.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide15.jpg"}, {"scene": 16, "visual": "쓰레기처리장 위치", "narration": "쓰레기처리장 위치 안내입니다.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide16.jpg"}, {"scene": 17, "visual": "메모장", "narration": "메모 페이지입니다.", "imageUrl": "https://ai-sop-training-system.vercel.app/assets/manuals/slko-slime-picnic/slide17.jpg"}]'::jsonb,
   '[{"question": "기본 체험 요금은 얼마인가요?", "options": ["12,000원", "15,000원", "18,000원", "20,000원"], "correct": 2, "explanation": "기본 체험 요금은 18,000원/1인입니다.", "type": "mc", "difficulty": "medium"}, {"question": "체험(이용) 시간은?", "options": ["30분", "1시간", "1시간 30분", "2시간"], "correct": 1, "explanation": "체험 시간은 1시간입니다.", "type": "mc", "difficulty": "medium"}, {"question": "권장 연령 기준은?", "options": ["만 1세 이상", "만 3세 이상", "만 5세 이상", "만 7세 이상"], "correct": 1, "explanation": "권장 연령은 만 3세 이상입니다.", "type": "mc", "difficulty": "medium"}, {"question": "8세 이하 어린이는 어떻게 입장하나요?", "options": ["혼자 입장 가능", "보호자 동반 필수", "입장 불가", "직원 동반"], "correct": 1, "explanation": "8세 이하는 보호자 동반이 필수입니다.", "type": "mc", "difficulty": "medium"}, {"question": "게임 1종을 추가 진행할 때 추가 요금은?", "options": ["+1,000원", "+2,000원", "+3,000원", "무료"], "correct": 2, "explanation": "게임 1종 추가 시 +3,000원입니다.", "type": "mc", "difficulty": "medium"}, {"question": "아이스크림 추가 구매 금액은?", "options": ["3,000원", "5,000원", "12,000원", "18,000원"], "correct": 2, "explanation": "아이스크림 추가 구매는 12,000원입니다.", "type": "mc", "difficulty": "medium"}, {"question": "파츠 1통 추가 구매 금액은?", "options": ["1,000원", "2,000원", "3,000원", "5,000원"], "correct": 2, "explanation": "파츠 1통은 3,000원입니다.", "type": "mc", "difficulty": "medium"}, {"question": "토핑 추가 구매 금액은?", "options": ["1,000원", "2,000원", "3,000원", "4,000원"], "correct": 1, "explanation": "토핑 추가는 2,000원입니다.", "type": "mc", "difficulty": "medium"}, {"question": "정원(아동) 기준 인원은?", "options": ["50명", "60명", "70명", "100명"], "correct": 2, "explanation": "정원은 아동 70명 기준입니다.", "type": "mc", "difficulty": "medium"}, {"question": "대형 바닥풍선 게임의 성공률은?", "options": ["80%", "90%", "95%", "97%"], "correct": 3, "explanation": "바닥풍선 성공률은 97%입니다.", "type": "mc", "difficulty": "medium"}, {"question": "슬라임 던지기 게임의 성공률은?", "options": ["70%", "80%", "90%", "97%"], "correct": 1, "explanation": "슬라임 던지기 성공률은 80%입니다.", "type": "mc", "difficulty": "medium"}, {"question": "대형 바닥풍선 게임의 인원 구성은?", "options": ["1인 1조", "2인 1조", "3인 1조", "4인 1조"], "correct": 1, "explanation": "바닥풍선은 2인 1조(강사와 협동)입니다.", "type": "mc", "difficulty": "medium"}, {"question": "슬라임이 옷에 묻었을 때 권장 세탁 방법은?", "options": ["뜨거운 물로 세탁", "미온수+식초로 녹인 후 세탁", "표백제 사용", "드라이클리닝만"], "correct": 1, "explanation": "미온수+식초로 녹인 뒤 가볍게 떼어내고 세탁합니다.", "type": "mc", "difficulty": "medium"}, {"question": "슬라임 월에 사용하는 슬라임 색상이 아닌 것은?", "options": ["파랑", "하늘", "하양", "빨강"], "correct": 3, "explanation": "슬라임 월 색상은 파랑·하늘·하양입니다.", "type": "mc", "difficulty": "medium"}, {"question": "POS 결제 시 고객에게 꼭 여쭤봐야 하는 것은?", "options": ["멤버십 가입", "신세계 포인트 적립", "영수증 필요 여부", "주차 등록"], "correct": 1, "explanation": "결제 시 신세계 포인트 적립 여부를 꼭 여쭤봅니다.", "type": "mc", "difficulty": "medium"}, {"question": "오픈 후 체험존·굿즈존 사진은 어떻게 처리하나요?", "options": ["본사 이메일 전송", "단톡방에 공유", "개인 보관", "SNS 업로드"], "correct": 1, "explanation": "오픈 후 체험존·굿즈존 사진을 단톡방에 공유합니다.", "type": "mc", "difficulty": "medium"}, {"question": "브랜드 슬라라의 핵심 가치는?", "options": ["재미, 친절, +1", "속도, 정확", "가격, 품질", "청결, 안전"], "correct": 0, "explanation": "슬라라의 가치는 ‘재미, 친절, +1’입니다.", "type": "mc", "difficulty": "medium"}]'::jsonb,
